use std::io::{self,Read};fn max_env(mut e:Vec<(i32,i32)>)->usize{e.sort_by(|a,b|if a.0==b.0{b.1.cmp(&a.1)}else{a.0.cmp(&b.0)});let mut tails:Vec<i32>=Vec::new();for(_,h)in e{let i=tails.binary_search(&h).unwrap_or_else(|x|x);if i==tails.len(){tails.push(h)}else{tails[i]=h}}tails.len()}fn main(){let mut s=String::new();io::stdin().read_to_string(&mut s).unwrap();let d:Vec<i32>=s.split_whitespace().map(|x|x.parse().unwrap()).collect();if d.is_empty(){return};let mut idx=0;let t=d[idx]as usize;idx+=1;let mut out=Vec::new();for _ in 0..t{let n=d[idx]as usize;idx+=1;let mut e=Vec::new();for _ in 0..n{e.push((d[idx],d[idx+1]));idx+=2;}out.push(max_env(e).to_string());}print!("{}",out.join("\n\n"));}
